mapper.select:
SELECT id, code, title, skill, level, topic, exam_type, script_text, storage_key, source, created_at
FROM dictation_clips
WHERE id = #{clipId}

SELECT lower(expected_word) AS word, count(*) AS miss_count
FROM dictation_misses
WHERE user_id = #{userId}
GROUP BY lower(expected_word)
ORDER BY miss_count DESC, word ASC
LIMIT #{limit}

SELECT id, user_id, sentence_text, source, storage_key, created_at
FROM dictation_practice_items
WHERE id = #{practiceItemId}
